using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents still use "Discriminator", so we must preserve it.
            entity.HasDiscriminator().HasValue("Blog");

            // Breaking change 2: EF 9 uses only the raw key for "id" (e.g. "1"),
            // instead of "Blog|1". Preserve the old format for existing data.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id");

            // Breaking change 3: Cosmos DB does not support indexes via EF Core.
            // HasIndex() now throws at runtime in EF 9 instead of silently ignoring.
            // REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}
