using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // BREAKING CHANGE 1 — Discriminator property renamed "$type" in EF 9.
            // Existing documents and raw SQL use "Discriminator". Preserve old name.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — "id" no longer synthesized as "Blog|1"; now just "1".
            // Existing documents have the old format. Use a shadow property with the
            // old composite format so EF can still find existing documents.
            entity.Property<string>("__id")
                  .ToJsonProperty("id")
                  .HasValueGeneratorFactory<LegacyCosmosIdGeneratorFactory>();

            // BREAKING CHANGE 3 — HasIndex() now throws for Cosmos provider instead
            // of being silently ignored. REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

// Value generator that reproduces the EF Core 8 "Discriminator|Key" id format.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Property("Discriminator").CurrentValue?.ToString()
                            ?? entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue?.ToString();
        return $"{discriminator}|{key}";
    }
}

class LegacyCosmosIdGeneratorFactory : ValueGeneratorFactory
{
    public override ValueGenerator Create(
        Microsoft.EntityFrameworkCore.Metadata.IProperty property,
        Microsoft.EntityFrameworkCore.Metadata.ITypeBase typeBase)
        => new LegacyCosmosIdGenerator();
}

